FROM jsonb_to_recordset('[{"id": "cap-109-english-reading-passage-16", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "reading_passage", "question_text": "(16-17)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "When it arrives,\nEveryone cheers.\nThe shirts and shorts dance\nOn the clothesline,\nThe trees and flowers wave\nLike they’re saying hi,\nAnd the clouds are so excited\nTo have a running race.\nWhen it comes,\nDad’s face falls.\nHis coat and jeans jump\nOff the clothesline\nInto the pond.\nThe tree leaves hop off\nAnd have a party on his new car.\nWhen it gets here,\nA lot of fun things I notice:\nThe pond’s face,\nSad and old with lines;\nMrs. Smith’s bread,\nDelicious and freshly baked.\nBut what smell is it?\nOh, no, it’s from Mr. Brown’s feet!\n leaf (leaves) 葉子", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": null, "intro_line": "(16-17)", "child_qnums": [16, 17]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-passage-18", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "reading_passage", "question_text": "(18-19)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Hey, guys! I have a lot of things I don’t need, so I’m\nthinking about having a yard sale. What do you think?\nHaving a yard sale is not easy. You have to collect things, put\nprices on them, put them out on tables and then wait for people\nto come. And usually you have to sell things at VERY low prices.\nFor all that time and work, you make very little money. Why not\njust sell your things online for higher prices?\nDebby’s right. But I think it’d be even better to just give your\nthings to people who need them. I just sent out a lot of things\nlast week.\nHey, I love yard sales! It’s a great chance to make big money if\nyou pick the right day. In my experience, Saturday is the best.\nI agree with Albert. You can make money and meet interesting\npeople. I made some good friends at my last yard sale.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": null, "intro_line": "(18-19)", "child_qnums": [18, 19]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-passage-20", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "reading_passage", "question_text": "(20-21)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Here is an ad for Sunny Market.\nFrom Jan. 4 to Feb. 4, for each $50 you spend With Sunny Sun pictures, you\n(on anything EXCEPT books and CDs) at Sunny can get one of the prizes below\nMarket, you’ll get a Sunny Sun picture     .     for free or at low prices!!\n(2 pictures for every $100, 3 pictures for every\n$150, …)                                   ★         Sunny ★Cup        Chocolate\n★ Collect 12 pictures, and you can get a Sunny\nCup for free!\n★ Collect 10 pictures, and you can get any of\nthe desserts on the right for free!    ★          Fruitcake\n★           Ice cream\n★ Collect 6 pictures, and you can buy a Sunny\nCup for $200, or any of the desserts on the\nright for $100!\n★       From Jan. 4 to Feb. 10, you can use Sunny\nSun pictures to get Sunny Cups or desserts.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": null, "intro_line": "(20-21)", "child_qnums": [20, 21]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-passage-22", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "reading_passage", "question_text": "(22-24)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Now I’m going to show you how to work with chocolate. I’ll\ndo it in a “bain-marie,” or, well, some people call it “water bath.”\nI myself love the name “bain-marie.” To make a “bain-marie,”\nyou need two pots, one bigger than the other.\nFirst, break the chocolate into small pieces and put them in the\nsmaller pot. Usually when making chocolate desserts, you’ll need to\nmix chocolate with butter and sugar. So if you do, put them in the\npot too.\nNow, half fill the bigger pot with warm water. Put the smaller\npot over the bigger one, and start to slowly mix the chocolate, the butter, and\nthe sugar together. Keep the water under 50ºC, or the chocolate may lose its\nshine. And make sure that no water goes in the smaller pot, or the chocolate will\nbecome hard and cannot be used.\nKeep mixing for about five to ten minutes, and the job is done. Easy, right?\n mix 混合", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": null, "intro_line": "(22-24)", "child_qnums": [22, 23, 24]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-passage-25", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "reading_passage", "question_text": "(25-27)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Taiwanese Bian-dang in Manhattan, New York City\n5/30/ 2014    by Eva Schmidt\nDuring lunch time, on 53rd Street, you’ll see\na long line of people in front of a Taiwanese food\ntruck for their “bian-dang,” a Taiwanese word for\n“lunch box.” On the menu you can find fried chicken with rice, pork dumplings,\ntea eggs, and other popular Taiwanese dishes.\nThe owners of the food truck are Thomas and Diana Yang, two\nTaiwanese-Americans. This brother-sister team started their business in 2009.\nBack then, there were a few Taiwanese restaurants in the city and several thousand\nfood trucks, but the Yangs were the first to sell Taiwanese food on a food truck.\nAt first, business was slack. People thought they were just another Chinese food\ntruck, and the food truck’s name, “Cravings,” often made people think of desserts, not\nlunch. Few people would stop by and try their food. “I couldn’t even give away free\nfood,” said Thomas. To catch people’s eye, they painted their truck blue, and drew\nTaiwan’s national flower, the plum blossom, on it. They also changed the food truck’s\nname to “bian-dang.” Soon people started to notice them, and business finally got\nbetter. Now on a good day, they can sell about 150 bian-dangs in about two hours.\nSo what’s next for Thomas and Diana? Well, they hope one day there will be a\nblock with Taiwanese food in the city, just like there is a Chinatown, a Korea Town,\nand a Little Italy. And their bian-dang food truck might just help to make that happen.\n national 國家的", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": null, "intro_line": "(25-27)", "child_qnums": [25, 26, 27]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-passage-28", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "reading_passage", "question_text": "(28-30)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "This is a letter by Selena Bieber to the students in her school.\nhttp://www.nvhsstudsup.org/openletter\nLater Is Better!\nSelena Bieber\nNorthville High School\nDo you feel it’s hard to get up early for school and even harder to listen\nwell in the first class at 8 a.m.? Well, this happens to most of us and is\nnot helpful for our learning!\nSome studies show that teenagers’ brains make melatonin, the hormone that\nhelps sleep, between 11 p.m. and 8 a.m. So it’s better for us to sleep during\nthese nine hours. But here comes the problem. We’re asked to get to school\nby 7:30 a.m. That means we have to get up before 7, when our brains\nshould still be sleeping. That’s why we’re always so tired and can’t think\nclearly in early morning classes. No clear head, no good learning, right?\nIf we can’t change how our body works, why can’t school start later? In\nthis way, we can not only sleep more but also learn better!\nWant to help us make it happen?\nVisit www.nvhsstudsup.org/later-better to learn more.\n brain 大腦 hormone 荷爾蒙", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": null, "intro_line": "(28-30)", "child_qnums": [28, 29, 30]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-passage-31", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "reading_passage", "question_text": "(31-34)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Kivalina, an island village in Alaska, USA,\nis known by only a few people. It cannot be\nfound on most maps of Alaska because it is\nonly 10 km2. This small Arctic village is home\nto 400 Inuit people*. However, their home\nwill become uninhabitable because the\nisland could be covered by the Chukchi\nSea by 2025. These Inuit people will have to leave their home.\nBut life now is already difficult. Over the past twenty years, winters have\nbecome warmer, the Arctic ice has kept melting, and the sea has been rising.\nThese changes have made it harder to live by hunting and fishing than before.\nWhat’s worse, there is no Arctic ice thick enough to keep them safe from terrible\nwind and rain.\nThese Inuit people think it is the oil and power companies in Alaska that\nhave brought all these troubles, but they are the ones who are paying the price.\nIt would cost hundreds of millions to move their village, and they have no idea\nwhere to get the money. Groups like ReLocate are working together with the\nInuit people to save Kivalina, but nobody is sure if their hard work will come to\nanything. All the Inuit people can do now is to pray the rising sea will not cover\ntheir home too soon.\n* The Inuit people are a group of people who live in the Arctic.\n melt 融化 hunt 打獵 company 公司", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": null, "intro_line": "(31-34)", "child_qnums": [31, 32, 33, 34]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-passage-35", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "reading_passage", "question_text": "(35-37)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "After a lot of tests and interviews, you finally got into a good school or got a good\njob.  But there’s a problem: it’s a long way from home.  “Well, I can take the bus or\ndrive,” you might think.  But before you decide whether it’s OK to have such a long\ncommute, it’s best to know 35 .\nHaving a long commute means you’ll get fewer hours of sleep, and that’ll make\nyou feel tired easily.  You’ll also have less time for friends and family, for exercise, or\nfor a nice meal.\nA long commute not only eats up your time but also 36 . Studies show that\npeople who have a long commute get fat easily and often have neck or back problems.\nIt’s easier for them to have heart problems too.   37 .  Studies find that these people\nget angry more often, feel less happy with their lives, and do less well at work.\nNow, does that good school or that good job still sound good to you?\n interview 面試 commute 通勤", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": null, "intro_line": "(35-37)", "child_qnums": [35, 36, 37]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-passage-38", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "reading_passage", "question_text": "(38-41)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "NOlympics in Munich\n11/11/2013\nPeople in the city of Munich have spoken their mind: they do not\nwant to host the Winter Olympics in 2022. To the cities that fight for this\nchance, 38 . The Olympics usually do a lot of good to the host city. The\nGames bring in jobs, visitors, and, most important of all, money. So why\ndid people in Munich say no?\nThe Olympics 39 for people in Munich. For them, the world’s\nbiggest sports festival could invite serious trouble. There would be a lot of\nbuilding work before the Games, and during the Games, too much traffic\nand too many visitors. Life would become terrible and nature would be\nhurt. And 40 : Munich hosted the 1972 Summer Olympics, and its\nneighbor, the mountain town Garmisch-Partenkirchen, hosted the 1936\nWinter Olympics.\nStill, the heavy price Munich paid does not worry the cities that are\nin the race to get the 2022 Winter Olympics.         41 , they are happy that\nMunich said no to the Olympics—their chances of getting the Games have\nbecome higher.\n host 舉辦 Olympics 奧運 visitor 遊客", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": null, "intro_line": "(38-41)", "child_qnums": [38, 39, 40, 41]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
  id text, exam_id text, subject_id text, paper_id text,
